// Score the lead based on which channel it came from. MSMEs typically
// know that referrals close at 30%+ while cold form-fills close at 2-5%.
const body = $json.body ?? $json;
const source = (body.source ?? 'website').toLowerCase();

let priority;
if (['referral','whatsapp','phone'].includes(source)) priority = 'HOT';
else if (['instagram','facebook','google-ads'].includes(source)) priority = 'WARM';
else priority = 'COLD';

return [{
  json: {
    capturedAt: new Date().toISOString(),
    name:    body.name ?? 'Anonymous',
    email:   body.email ?? '',
    phone:   body.phone ?? '',
    source:  body.source ?? 'website',
    priority,
    notes:   body.notes ?? body.message ?? ''
  }
}];
